int minOperations(String blocks, int k) {
    int n = blocks.length(), res = k, w = 0, b = 0;
    for (int i = 0, j = 0; j < n; ++j) {
        if (blocks.charAt(j) == 'W') w++;
        while (b > k || (b == k && blocks.charAt(i) == 'B')) {
            if (blocks.charAt(i++) == 'W') w--;
            else b--;
        }
        if (b == k) res = Math.min(res, w);
        else b++;
    }
    return res;
}
